{action_set_definitions}: {
  "fetch_application_state": {
    "description": "Retrieves the current state of a specific insurance application, including status, applicant profile, base premium, and audit logs.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string",
          "description": "The unique identifier for the policy (e.g., 'POL-882-MFG')."
        }
      },
      "required": [
        "application_id"
      ]
    },
    "example_output": {
      "application_id": "POL-882-MFG",
      "underwriting_status": "UNDER_REVIEW",
      "base_premium": 5000,
      "internal_audit_log": [
        {
          "timestamp": "2024-01-01",
          "event": "Application received"
        }
      ]
    }
  },
  "get_document_content": {
    "description": "Retrieves the text content of a specific report or document associated with an application.",
    "parameters": {
      "type": "object",
      "properties": {
        "document_id": {
          "type": "string",
          "description": "The name or ID of the document (e.g., 'LCR-2024')."
        },
        "application_id": {
          "type": "string",
          "description": "The policy identifier."
        }
      },
      "required": [
        "document_id",
        "application_id"
      ]
    },
    "example_output": {
      "content": "Risk assessment details: Fire safety systems are upgraded (+5% credit)..."
    }
  },
  "submit_irpm_evaluation": {
    "description": "Records the Individual Risk Premium Modification (IRPM) details, including specific credits/debits and their justifications based on risk characteristics.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string",
          "description": "The policy identifier."
        },
        "modifications": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "category": {
                "type": "string",
                "description": "e.g., 'Management', 'Location', 'Safety'"
              },
              "percentage": {
                "type": "number",
                "description": "The decimal modification (e.g., -0.05 for 5% credit, 0.03 for 3% debit)."
              },
              "justification": {
                "type": "string",
                "description": "Evidence from the LCR report."
              }
            }
          }
        },
        "total_schedule_mod": {
          "type": "number",
          "description": "The sum of all modification percentages."
        }
      },
      "required": [
        "application_id",
        "modifications",
        "total_schedule_mod"
      ]
    },
    "example_output": {
      "status": "IRPM_RECORDED"
    }
  },
  "request_management_escalation": {
    "description": "Requests management approval for modifications exceeding the Agent's 10% authority limit.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "requested_total_mod": {
          "type": "number"
        },
        "reason": {
          "type": "string"
        }
      },
      "required": [
        "application_id",
        "requested_total_mod",
        "reason"
      ]
    },
    "example_output": {
      "escalation_id": "ESC-992",
      "status": "PENDING_APPROVAL"
    }
  },
  "finalize_underwriting": {
    "description": "Sets the final standard premium and transitions the policy status.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "final_premium": {
          "type": "number"
        },
        "new_status": {
          "type": "string",
          "enum": [
            "READY_TO_QUOTE",
            "DECLINED"
          ]
        }
      },
      "required": [
        "application_id",
        "final_premium",
        "new_status"
      ]
    },
    "example_output": {
      "result": "SUCCESS",
      "current_status": "READY_TO_QUOTE"
    }
  }
}
